export const CERMAM_GERADO_2026_QUESTIONS: any[] = [
  { id: 'cermam_gerado26_001', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Ginecologia & Obstetrícia', text: 'Gestante de 32 semanas, com PA 168/108 mmHg em duas aferições, cefaleia occipital e escotomas visuais. Assinale a conduta imediata.', options: ['Sulfato de magnésio e avaliação para resolução da gestação.', 'Repouso domiciliar, sem qualquer medicação.', 'Anti-hipertensivo oral ambulatorial isolado.', 'Apenas analgésico comum para a cefaleia, sem outra intervenção.'], correctIndex: 0, explanation: 'PA muito elevada com sintomas premonitórios caracteriza pré-eclâmpsia grave, exigindo sulfato de magnésio e avaliação para resolução da gestação. Repouso domiciliar sem medicação não trata a gravidade do quadro; anti-hipertensivo oral ambulatorial isolado é insuficiente diante de sinais premonitórios; analgésico comum isolado não trata a causa hipertensiva.' },
  { id: 'cermam_gerado26_002', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Ginecologia & Obstetrícia', text: 'Gestante de 30 semanas, hipertensa, com dor abdominal súbita, hipertonia uterina, sangramento vaginal escuro e sofrimento fetal agudo. Assinale o diagnóstico e a conduta.', options: ['Descolamento prematuro de placenta; interrupção imediata da gestação.', 'Placenta prévia; conduta expectante.', 'Rotura uterina espontânea; observação clínica.', 'Corioamnionite; apenas antibioticoterapia, sem resolução da gestação.'], correctIndex: 0, explanation: 'Dor súbita, hipertonia uterina e sofrimento fetal em gestante hipertensa são clássicos de descolamento prematuro de placenta, exigindo interrupção imediata. Placenta prévia cursa com sangramento indolor sem hipertonia; rotura uterina espontânea é rara sem cicatriz uterina prévia; corioamnionite cursaria com febre materna.' },
  { id: 'cermam_gerado26_003', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Ginecologia & Obstetrícia', text: 'Puérpera imediata, após tração do cordão umbilical durante a dequitação, apresenta sangramento vaginal importante, dor intensa e massa arroxeada visível exteriorizada pelo intróito vaginal, com fundo uterino não palpável ao exame abdominal. Assinale o diagnóstico e a conduta imediata.', options: ['Inversão uterina aguda; reposicionamento manual imediato do útero, com suporte hemodinâmico simultâneo.', 'Atonia uterina; massagem uterina bimanual isolada, sem qualquer outra manobra.', 'Retenção de placenta acreta; histerectomia de urgência como primeira conduta, sem tentativa de reposicionamento.', 'Laceração cervical isolada; sutura cervical isolada, sem qualquer outra avaliação.'], correctIndex: 0, explanation: 'Massa exteriorizada pelo intróito com fundo uterino não palpável após tração do cordão é o quadro clássico de inversão uterina aguda, exigindo reposicionamento manual imediato com suporte hemodinâmico. Atonia uterina não explica a massa exteriorizada nem a ausência do fundo uterino à palpação abdominal; histerectomia de urgência sem tentativa de reposicionamento é desproporcional como primeira conduta; laceração cervical isolada não explica esse achado de massa exteriorizada com útero invertido.' },
  { id: 'cermam_gerado26_004', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Ginecologia & Obstetrícia', text: 'Gestante Rh negativo, parceiro Rh positivo, 28 semanas, Coombs indireto negativo. Assinale a conduta profilática.', options: ['Imunoglobulina anti-D profilática.', 'Nenhuma conduta específica.', 'Transfusão intrauterina profilática.', 'Interrupção antecipada da gestação.'], correctIndex: 0, explanation: 'Gestante Rh negativo não sensibilizada deve receber imunoglobulina anti-D por volta da 28ª semana para prevenir aloimunização. Não realizar conduta específica expõe ao risco de sensibilização futura; transfusão intrauterina é tratamento de anemia fetal já estabelecida; interrupção antecipada não tem indicação nessa situação.' },
  { id: 'cermam_gerado26_005', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Ginecologia & Obstetrícia', text: 'Mulher de 26 anos, com corrimento vaginal amarelo-esverdeado, prurido intenso e colo uterino com aspecto de "morango" ao exame especular. Assinale o agente etiológico mais provável e a conduta.', options: ['Trichomonas vaginalis; metronidazol para a paciente e o(s) parceiro(s) sexual(is).', 'Candida albicans; antifúngico tópico isolado, sem tratamento do parceiro.', 'Gardnerella vaginalis; metronidazol, sem necessidade de tratar o parceiro.', 'Chlamydia trachomatis; azitromicina isolada, sem relação com o achado de colo em "morango".'], correctIndex: 0, explanation: 'O colo em aspecto de "morango" associado a corrimento e prurido é achado clássico de tricomoníase, tratada com metronidazol e tratamento do parceiro. Candida causa corrimento em grumos sem esse aspecto de colo; Gardnerella não costuma causar prurido intenso; clamídia não é a etiologia mais associada a esse achado.' },
  { id: 'cermam_gerado26_006', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Ginecologia & Obstetrícia', text: 'Mulher de 60 anos, menopausada, com sangramento vaginal e ultrassom evidenciando espessamento endometrial de 12 mm. Assinale a conduta diagnóstica mais apropriada.', options: ['Biópsia endometrial (por curetagem, histeroscopia ou outro método adequado).', 'Observação clínica isolada, sem investigação adicional.', 'Histerectomia imediata, sem biópsia prévia.', 'Terapia hormonal isolada, sem investigação da causa do sangramento.'], correctIndex: 0, explanation: 'Sangramento pós-menopausa com espessamento endometrial exige biópsia para investigação histológica. Observação isolada atrasa perigosamente o diagnóstico; histerectomia sem biópsia prévia é desproporcional; terapia hormonal isolada não investiga a causa nem exclui malignidade.' },
  { id: 'cermam_gerado26_007', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Ginecologia & Obstetrícia', text: 'Mulher de 27 anos, casada há 2 anos, relata dor intensa e incapacidade de penetração vaginal em todas as tentativas de relação sexual, com contração involuntária da musculatura perineal ao exame especular, sem lesão anatômica identificável. Assinale o diagnóstico mais provável e a abordagem terapêutica inicial.', options: ['Vaginismo; abordagem multidisciplinar incluindo terapia sexual e exercícios progressivos de dessensibilização (como uso de dilatadores vaginais).', 'Vulvovaginite candidiásica; antifúngico tópico isolado, sem qualquer abordagem psicológica.', 'Endometriose profunda; laparoscopia diagnóstica imediata como primeira conduta.', 'Líquen escleroso vulvar; corticoide tópico de alta potência isolado, sem qualquer outra abordagem.'], correctIndex: 0, explanation: 'Contração involuntária da musculatura perineal impedindo a penetração, sem lesão anatômica identificável, caracteriza o vaginismo, abordado com terapia sexual e dessensibilização progressiva. A candidíase apresentaria corrimento e sinais inflamatórios visíveis à inspeção; a endometriose profunda cursaria com dispareunia de profundidade associada a outros achados, não com esse espasmo involuntário impeditivo; o líquen escleroso apresentaria alterações cutâneas vulvares visíveis ao exame, ausentes no caso.' },
  { id: 'cermam_gerado26_008', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Ginecologia & Obstetrícia', text: 'Mulher de 32 anos, sexualmente ativa, com dor pélvica, febre e corrimento cervical purulento, dor à mobilização do colo uterino. Assinale a conduta mais apropriada.', options: ['Iniciar antibioticoterapia empírica de amplo espectro para doença inflamatória pélvica, cobrindo gonococo e clamídia.', 'Aguardar resultado de cultura antes de iniciar qualquer tratamento.', 'Indicar laparotomia exploradora imediata, independente da gravidade.', 'Iniciar apenas analgésico, sem qualquer antibioticoterapia.'], correctIndex: 0, explanation: 'A suspeita clínica de doença inflamatória pélvica justifica antibioticoterapia empírica imediata cobrindo gonococo e clamídia. Aguardar cultura atrasa o tratamento; laparotomia é reservada a complicações; analgésico isolado não trata a infecção subjacente.' },
  { id: 'cermam_gerado26_009', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Ginecologia & Obstetrícia', text: 'Mulher de 45 anos, com sangramento uterino aumentado e prolongado, ultrassom evidenciando múltiplos miomas intramurais, sem desejo reprodutivo. Assinale uma opção de tratamento clínico, antes de considerar cirurgia.', options: ['Dispositivo intrauterino liberador de levonorgestrel.', 'Histerectomia como única opção terapêutica disponível.', 'Embolização das artérias uterinas como primeira opção obrigatória, sem tentativa clínica prévia.', 'Observação isolada, sem qualquer tratamento.'], correctIndex: 0, explanation: 'O DIU de levonorgestrel é opção clínica eficaz para reduzir o sangramento em mulheres com miomas sem desejo reprodutivo. Histerectomia não é a única opção; embolização não precisa ser a primeira opção obrigatória; observação isolada não é apropriada diante de sangramento sintomático.' },
  { id: 'cermam_gerado26_010', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Ginecologia & Obstetrícia', text: 'Gestante de 38 semanas, em trabalho de parto, cardiotocografia evidenciando desacelerações tardias repetidas coincidindo com contrações uterinas regulares. Assinale a interpretação e a conduta.', options: ['Sugestivo de insuficiência uteroplacentária; medidas de ressuscitação intrauterina e avaliação para resolução do parto.', 'Padrão normal e tranquilizador, sem necessidade de intervenção.', 'Desacelerações precoces por compressão da cabeça fetal, sem necessidade de conduta adicional.', 'Taquissistolia uterina isolada, sem relação com o padrão de frequência cardíaca fetal.'], correctIndex: 0, explanation: 'Desacelerações tardias repetidas sugerem insuficiência uteroplacentária, exigindo ressuscitação intrauterina e avaliação para resolução do parto. Não é padrão normal; desacelerações precoces têm timing diferente; taquissistolia não é sinônimo do padrão descrito.' },
  { id: 'cermam_gerado26_011', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Ginecologia & Obstetrícia', text: 'Mulher de 31 anos, com atraso menstrual de 7 semanas, dor pélvica unilateral e sangramento vaginal discreto, beta-hCG positivo, ultrassonografia sem saco gestacional intrauterino e imagem anexial suspeita. Assinale a hipótese e a conduta inicial em paciente estável.', options: ['Gravidez ectópica; considerar tratamento com metotrexato ou cirúrgico, conforme critérios de elegibilidade.', 'Abortamento completo; apenas orientação e alta.', 'Mola hidatiforme completa; esvaziamento uterino imediato, sem dosagem seriada de beta-hCG.', 'Gestação tópica inicial normal; apenas repetir a ultrassonografia em 6 meses.'], correctIndex: 0, explanation: 'Beta-hCG positivo sem saco gestacional intrauterino e imagem anexial suspeita sugerem gravidez ectópica, tratável com metotrexato ou cirurgia em paciente estável. Abortamento completo não explicaria a imagem anexial; mola hidatiforme cursaria com útero maior e padrão ultrassonográfico característico; gestação tópica normal seria incompatível com a ausência de saco gestacional.' },
  { id: 'cermam_gerado26_012', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Ginecologia & Obstetrícia', text: 'Mulher de 38 anos, com dismenorreia progressiva, dispareunia de profundidade e infertilidade, ressonância evidenciando endometrioma ovariano bilateral. Assinale o diagnóstico mais provável.', options: ['Endometriose.', 'Miomatose uterina submucosa isolada.', 'Doença inflamatória pélvica aguda.', 'Síndrome de Asherman.'], correctIndex: 0, explanation: 'Dismenorreia progressiva, dispareunia de profundidade, infertilidade e endometrioma ovariano bilateral são compatíveis com endometriose. Miomatose submucosa cursaria com sangramento aumentado; doença inflamatória pélvica aguda cursa com quadro infeccioso agudo; síndrome de Asherman relaciona-se a aderências intrauterinas.' },
  { id: 'cermam_gerado26_013', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Ginecologia & Obstetrícia', text: 'Mulher de 35 anos, no puerpério imediato, com febre de 38,8°C, mama esquerda hiperemiada e dolorosa, sem flutuação. Assinale a conduta mais apropriada.', options: ['Manutenção do aleitamento materno (inclusive na mama afetada) associada a antibioticoterapia para mastite puerperal.', 'Suspensão obrigatória do aleitamento materno em ambas as mamas.', 'Drenagem cirúrgica imediata, independente da ausência de sinais de abscesso.', 'Apenas anti-inflamatório, sem qualquer antibioticoterapia.'], correctIndex: 0, explanation: 'Mastite puerperal sem sinais de abscesso é tratada com antibioticoterapia e manutenção do aleitamento, favorecendo o esvaziamento. Suspender o aleitamento pode piorar a estase láctea; drenagem é reservada a abscessos já formados; anti-inflamatório isolado não trata o quadro infeccioso.' },
  { id: 'cermam_gerado26_014', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Ginecologia & Obstetrícia', text: 'Gestante de 32 semanas, com perda súbita de líquido claro pela vagina há 6 horas, confirmada ao exame especular, sem contrações regulares, sem febre, com boa vitalidade fetal. Assinale a conduta mais apropriada.', options: ['Internação para conduta expectante com corticoide para maturação pulmonar fetal, antibioticoprofilático e vigilância rigorosa de sinais de infecção.', 'Indução do parto imediata, independente da idade gestacional e da ausência de sinais de corioamnionite.', 'Alta hospitalar com orientação de retorno apenas se houver febre, sem qualquer conduta hospitalar inicial.', 'Cerclagem cervical de urgência, independente da ausência de indicação para esse procedimento nesse contexto.'], correctIndex: 0, explanation: 'Rotura prematura de membranas pré-termo, sem sinais de infecção, é conduzida de forma expectante com corticoide para maturação pulmonar, antibioticoprofilaxia e vigilância rigorosa, visando prolongar a gestação com segurança. Indução imediata expõe o feto aos riscos da prematuridade sem benefício claro na ausência de infecção; alta sem conduta hospitalar inicial ignora o risco de corioamnionite e prolapso de cordão; cerclagem não tem indicação nesse contexto de rotura de membranas já estabelecida.' },
  { id: 'cermam_gerado26_015', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Ginecologia & Obstetrícia', text: 'Mulher de 55 anos, na pós-menopausa, com sangramento vaginal há 2 semanas, ultrassonografia com espessamento endometrial de 14 mm. Assinale a conduta diagnóstica mais apropriada.', options: ['Biópsia endometrial (por histeroscopia, curetagem ou outro método adequado).', 'Observação clínica isolada, sem qualquer investigação adicional.', 'Colposcopia isolada, sem avaliação endometrial.', 'Terapia hormonal isolada, sem investigação da causa do sangramento.'], correctIndex: 0, explanation: 'Sangramento pós-menopausa com espessamento endometrial significativo exige biópsia. Observação isolada atrasa o diagnóstico; colposcopia avalia o colo uterino, não o endométrio; terapia hormonal isolada não investiga a causa nem exclui malignidade.' },
  { id: 'cermam_gerado26_016', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Ginecologia & Obstetrícia', text: 'Mulher de 24 anos, nuligesta, deseja iniciar contraceptivo hormonal combinado, sem contraindicações. Assinale a alternativa correta sobre a orientação do método.', options: ['O uso correto confere alta eficácia contraceptiva, mas não protege contra infecções sexualmente transmissíveis.', 'O método protege completamente contra todas as infecções sexualmente transmissíveis, dispensando preservativo.', 'Deve ser suspenso obrigatoriamente a cada 3 meses por um mês, para "descanso hormonal".', 'É contraindicado em todas as mulheres nulíparas, independente de outros fatores de risco.'], correctIndex: 0, explanation: 'O contraceptivo combinado tem alta eficácia contraceptiva, mas não protege contra ISTs, sendo necessário associar preservativo. Afirmar proteção completa é incorreto; não há recomendação de "descanso hormonal" periódico; não há contraindicação para nulíparas em geral.' },
  { id: 'cermam_gerado26_017', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Ginecologia & Obstetrícia', text: 'Gestante de 40 semanas, em trabalho de parto ativo, parada da progressão por 2 horas apesar de contrações adequadas, apresentação cefálica insinuada e dilatação total. Assinale a hipótese e a conduta.', options: ['Desproporção cefalopélvica ou parada secundária da descida; considerar parto instrumental ou cesariana.', 'Trabalho de parto normal em progressão fisiológica; apenas aguardar, sem reavaliação.', 'Rotura uterina; observação clínica isolada.', 'Distocia de ombro; manobra de McRoberts imediata, antes da expulsão da cabeça fetal.'], correctIndex: 0, explanation: 'Parada da progressão apesar de contrações adequadas, com dilatação total, sugere desproporção cefalopélvica ou parada secundária, exigindo avaliação para parto instrumental ou cesariana. Não é progressão fisiológica normal; rotura uterina teria sinais mais agudos; a manobra de McRoberts é usada após a expulsão da cabeça, não antes.' },
  { id: 'cermam_gerado26_018', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Ginecologia & Obstetrícia', text: 'Mulher de 45 anos, com sangramento uterino aumentado, biópsia de endométrio confirmando hiperplasia endometrial sem atipia, sem desejo reprodutivo. Assinale a conduta de primeira linha.', options: ['Progestagênio (oral ou dispositivo intrauterino liberador de levonorgestrel), com reavaliação histológica.', 'Histerectomia como única opção terapêutica disponível.', 'Quimioterapia sistêmica, considerando a hiperplasia sem atipia equivalente a câncer invasivo.', 'Observação isolada sem qualquer tratamento, independente do risco de progressão.'], correctIndex: 0, explanation: 'A hiperplasia sem atipia é tratada em primeira linha com progestagênio, com reavaliação histológica. Histerectomia não é a primeira linha; hiperplasia sem atipia não é equivalente a câncer invasivo; observação isolada ignora o risco de progressão.' },
  { id: 'cermam_gerado26_019', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Ginecologia & Obstetrícia', text: 'Gestante de 26 semanas, com pressão arterial de 170/115 mmHg, cefaleia intensa persistente, escotomas visuais e dor em hipocôndrio direito, proteinúria maciça. Assinale a conduta imediata.', options: ['Sulfato de magnésio para prevenção de convulsões e avaliação para resolução da gestação.', 'Anti-hipertensivo oral ambulatorial isolado, sem necessidade de internação.', 'Repouso domiciliar com reavaliação em 7 dias, sem medicação imediata.', 'Apenas analgésico comum para a cefaleia, sem qualquer outra intervenção.'], correctIndex: 0, explanation: 'Hipertensão grave com sintomas premonitórios caracteriza pré-eclâmpsia grave, exigindo sulfato de magnésio e avaliação para resolução da gestação. Anti-hipertensivo oral isolado é insuficiente; repouso domiciliar com reavaliação tardia é perigoso; analgésico isolado não trata a causa hipertensiva.' },
  { id: 'cermam_gerado26_020', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Lactente de 4 meses, com vômitos em jato pós-prandiais, oliva palpável em epigástrio, alcalose metabólica hipoclorêmica. Assinale a conduta antes da cirurgia.', options: ['Correção do distúrbio hidroeletrolítico.', 'Cirurgia imediata sem correção prévia.', 'Antibioticoterapia isolada.', 'Observação isolada por 30 dias, sem qualquer intervenção.'], correctIndex: 0, explanation: 'Na estenose hipertrófica do piloro, o distúrbio hidroeletrolítico deve ser corrigido antes da piloromiotomia. Cirurgia imediata sem correção aumenta o risco anestésico-metabólico; antibioticoterapia não trata a obstrução mecânica; observação prolongada agrava a desidratação.' },
  { id: 'cermam_gerado26_021', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Criança de 3 anos, com febre há 6 dias, língua em framboesa, edema de mãos e pés, exantema polimorfo. Assinale a principal complicação a ser monitorada.', options: ['Aneurisma de artérias coronárias.', 'Insuficiência renal crônica.', 'Meningite bacteriana.', 'Insuficiência hepática aguda.'], correctIndex: 0, explanation: 'Esse quadro é típico da doença de Kawasaki, cuja principal complicação a prevenir com imunoglobulina é o aneurisma coronariano. As demais opções não têm relação fisiopatológica direta com essa vasculite.' },
  { id: 'cermam_gerado26_022', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Lactente de 10 meses, com choro intenso intermitente, letargia, fezes em "geleia de framboesa", massa palpável em hipocôndrio direito. Assinale a conduta inicial.', options: ['Redução por enema hidrostático guiado por imagem.', 'Apendicectomia imediata.', 'Cintilografia como tratamento definitivo.', 'Apenas hidratação oral, sem qualquer outra conduta.'], correctIndex: 0, explanation: 'Esse quadro clássico de invaginação intestinal é inicialmente tratado por redução não cirúrgica com enema guiado por imagem. Apendicectomia não trata a invaginação; cintilografia não é modalidade terapêutica; hidratação oral isolada não resolve a obstrução mecânica.' },
  { id: 'cermam_gerado26_023', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Criança de 6 anos, com enurese noturna isolada e exame físico normal. Assinale a conduta inicial.', options: ['Orientação comportamental e reasseguramento.', 'Desmopressina imediata sem orientação comportamental prévia.', 'Investigação urológica invasiva imediata.', 'Restrição hídrica extrema durante todo o dia.'], correctIndex: 0, explanation: 'Enurese isolada sem sinais de alarme é tratada inicialmente com orientação comportamental. Desmopressina imediata pula uma etapa de primeira linha; investigação invasiva não é indicada sem sinais de alarme; restrição hídrica extrema é inadequada.' },
  { id: 'cermam_gerado26_024', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Criança de 6 anos, com sete episódios de otite média aguda no último ano, apesar de tratamento antibiótico adequado em cada episódio, apresentando também hipoacusia persistente entre as crises e otoscopia com efusão residual. Assinale a conduta mais apropriada.', options: ['Encaminhamento para avaliação otorrinolaringológica com consideração de timpanostomia com tubo de ventilação, dada a otite média recorrente com efusão persistente.', 'Antibioticoterapia profilática contínua por tempo indeterminado como única conduta, sem encaminhamento especializado.', 'Observação isolada, sem qualquer encaminhamento, pois otites recorrentes não trazem repercussão auditiva relevante na infância.', 'Adenoidectomia isolada, sem qualquer avaliação da função auditiva ou consideração de tubo de ventilação.'], correctIndex: 0, explanation: 'Otite média aguda recorrente com efusão persistente e hipoacusia associada tem indicação de avaliação otorrinolaringológica especializada, com consideração de tubo de ventilação para reduzir recorrências e proteger a audição. Antibioticoterapia profilática contínua isolada não é a conduta padrão diante dessa recorrência com efusão persistente; observação isolada ignora o risco de repercussão auditiva e de linguagem na infância; adenoidectomia isolada, sem avaliação completa e sem considerar o tubo de ventilação, não aborda adequadamente o problema descrito.' },
  { id: 'cermam_gerado26_025', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Recém-nascido pré-termo, 29 semanas, com cateter venoso central há 12 dias, apresenta instabilidade térmica, distensão abdominal e piora do estado geral, sem foco infeccioso evidente ao exame inicial. Assinale a conduta mais apropriada.', options: ['Coletar hemoculturas (periférica e do cateter) e iniciar antibioticoterapia empírica de amplo espectro para sepse neonatal tardia associada a cateter, sem aguardar confirmação laboratorial.', 'Aguardar resultado de hemocultura antes de iniciar qualquer antibioticoterapia, dada a ausência de foco infeccioso evidente.', 'Remover o cateter venoso central como única conduta, sem qualquer antibioticoterapia sistêmica.', 'Observação clínica isolada por 24 horas, sem qualquer coleta de exames ou intervenção terapêutica.'], correctIndex: 0, explanation: 'Sinais inespecíficos de piora clínica em prematuro com cateter venoso central sugerem sepse neonatal tardia associada a cateter, exigindo coleta de hemoculturas e início empírico imediato de antibioticoterapia, dado o risco de deterioração rápida. Aguardar a hemocultura antes de tratar atrasa perigosamente o tratamento; remover o cateter sem antibioticoterapia sistêmica não trata uma infecção já sistêmica; observação isolada por 24 horas sem qualquer intervenção é perigosa diante de sinais de piora clínica.' },
  { id: 'cermam_gerado26_026', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Lactente de 2 meses, com tosse paroxística seguida de guincho inspiratório e cianose, sem febre, contactante domiciliar com adulto tossindo há semanas. Assinale o diagnóstico e a conduta.', options: ['Coqueluche; antibioticoterapia com macrolídeo, além de suporte respiratório conforme necessidade.', 'Bronquiolite viral aguda; apenas suporte clínico, sem investigação específica do contactante.', 'Asma brônquica; broncodilatador isolado, sem necessidade de antibioticoterapia.', 'Refluxo gastroesofágico; apenas espessamento da dieta láctea.'], correctIndex: 0, explanation: 'Tosse paroxística com guincho, cianose e contactante com tosse prolongada sugerem coqueluche, tratada com macrolídeo e suporte respiratório. Bronquiolite cursa com sibilância; asma é rara nessa idade; refluxo não explica o contexto epidemiológico.' },
  { id: 'cermam_gerado26_027', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Recém-nascido pré-termo de 30 semanas, em ventilação mecânica desde o nascimento, aos 10 dias apresenta distensão abdominal, resíduo gástrico bilioso e pneumatose intestinal na radiografia. Assinale a conduta inicial.', options: ['Suspensão da dieta enteral, antibioticoterapia sistêmica e suporte clínico, com avaliação cirúrgica conforme evolução.', 'Manutenção da dieta enteral com espessamento, sem suspensão da via oral.', 'Apendicectomia de urgência, sem suporte clínico prévio.', 'Gastrostomia isolada, sem qualquer suporte clínico adicional.'], correctIndex: 0, explanation: 'Distensão, resíduo bilioso e pneumatose intestinal em prematuro são achados clássicos de enterocolite necrosante, tratada com suspensão da dieta, antibioticoterapia e suporte clínico. Manter a dieta agravaria o quadro; apendicite neonatal é rara; gastrostomia isolada não trata o processo agudo.' },
  { id: 'cermam_gerado26_028', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Criança de 7 anos, com poliúria, polidipsia e perda ponderal há 3 semanas, glicemia capilar de 420 mg/dL, cetonúria positiva, gasometria com pH 7,18 e bicarbonato de 10 mEq/L. Assinale o diagnóstico e a conduta inicial prioritária.', options: ['Cetoacidose diabética; hidratação venosa e insulinoterapia contínua, com monitorização eletrolítica rigorosa.', 'Diabetes insípido central; restrição hídrica rigorosa como primeira conduta.', 'Síndrome hiperosmolar hiperglicêmica não cetótica; apenas insulina em bolus, sem hidratação prévia.', 'Hipoglicemia cetótica da infância; oferta isolada de glicose oral.'], correctIndex: 0, explanation: 'Hiperglicemia, cetonúria e acidose metabólica caracterizam cetoacidose diabética, tratada com hidratação venosa e insulinoterapia, monitorando o potássio. Diabetes insípido cursaria sem hiperglicemia; a síndrome hiperosmolar é mais típica de adultos; hipoglicemia cetótica cursa com glicemia baixa.' },
  { id: 'cermam_gerado26_029', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Criança de 4 anos, frequentadora de creche, com prurido intenso de piora noturna, pápulas eritematosas e lesões lineares (túneis) em espaços interdigitais das mãos, punhos e região abdominal, com relato de lesões semelhantes em outros familiares que residem na mesma casa. Assinale o diagnóstico e a conduta.', options: ['Escabiose; permetrina tópica, com tratamento simultâneo de todos os contactantes domiciliares, independente de sintomas.', 'Dermatite atópica; corticoide tópico isolado, sem necessidade de tratar os familiares.', 'Pediculose corporal; apenas medidas de higiene, sem tratamento medicamentoso específico.', 'Urticária aguda idiopática; anti-histamínico isolado, sem qualquer relação com os familiares afetados.'], correctIndex: 0, explanation: 'Prurido noturno com túneis interdigitais e lesões semelhantes em familiares da mesma casa são característicos da escabiose, tratada com permetrina tópica e tratamento simultâneo de todos os contactantes domiciliares, mesmo assintomáticos, para evitar reinfestação. A dermatite atópica não explica os túneis característicos nem o acometimento simultâneo de familiares; a pediculose corporal acomete o corpo de forma diferente, sem esses túneis interdigitais típicos; a urticária aguda não explica as lesões lineares características nem o padrão de contágio familiar.' },
  { id: 'cermam_gerado26_030', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Lactente de 9 meses, previamente hígido, com tosse, coriza e sibilância há 2 dias, desconforto respiratório leve, primeiro episódio de sibilância, teste rápido positivo para vírus sincicial respiratório. Assinale a conduta.', options: ['Suporte com lavagem nasal, oxigenoterapia se necessário e hidratação, sem broncodilatador, corticoide ou antibiótico de rotina.', 'Corticoide sistêmico em dose única, indicado rotineiramente para reduzir o tempo de internação.', 'Antibioticoterapia empírica de rotina, dada a alta taxa de coinfecção bacteriana.', 'Broncodilatador inalatório de rotina e continuado em todos os casos.'], correctIndex: 0, explanation: 'O tratamento da bronquiolite viral aguda é essencialmente de suporte, sem benefício comprovado de broncodilatador, corticoide ou antibiótico de rotina. Corticoide sistêmico não reduz tempo de internação; antibioticoterapia empírica não é indicada sem sinais de infecção bacteriana; broncodilatador de rotina não tem eficácia comprovada.' },
  { id: 'cermam_gerado26_031', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Recém-nascido, filho de mãe com sorologia positiva para sífilis não tratada adequadamente na gestação, assintomático ao nascimento, VDRL do recém-nascido maior que o materno. Assinale a conduta mais adequada.', options: ['Investigação completa (líquor, radiografia de ossos longos, hemograma) e tratamento com penicilina cristalina.', 'Apenas seguimento sorológico ambulatorial, sem qualquer tratamento.', 'Tratamento com penicilina benzatina em dose única, sem investigação complementar.', 'Aguardar sintomas antes de iniciar qualquer investigação ou tratamento.'], correctIndex: 0, explanation: 'Título do recém-nascido maior que o materno, associado a tratamento materno inadequado, exige investigação completa e tratamento com penicilina cristalina, mesmo assintomático. Apenas seguimento sem tratamento é insuficiente; penicilina benzatina isolada sem investigação é esquema inadequado; aguardar sintomas atrasa o tratamento.' },
  { id: 'cermam_gerado26_032', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Menino de 5 anos, com claudicação e dor na perna direita há 24 horas, sem febre, quadro gripal autolimitado há 1 semana, posição antálgica do joelho e rotação externa do membro. Assinale a abordagem mais apropriada.', options: ['Ultrassonografia de quadril para avaliar sinovite transitória, com manejo sintomático e observação.', 'Antibioticoterapia empírica de amplo espectro imediata, sem qualquer investigação prévia.', 'Punção articular de urgência, independente da ausência de febre e sinais de toxemia.', 'Ressonância magnética de coluna lombar como primeiro exame, sem avaliação do quadril.'], correctIndex: 0, explanation: 'Claudicação após quadro viral, sem febre ou toxemia, é compatível com sinovite transitória do quadril, investigada com ultrassonografia e manejada com sintomáticos. Antibioticoterapia empírica imediata é desproporcional; punção articular não é indicada sem sinais de toxemia; ressonância de coluna não é o exame direcionado.' },
  { id: 'cermam_gerado26_033', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Recém-nascido a termo, filho de mãe com sorologia HBsAg positiva identificada no pré-natal, sem dados sobre a carga viral materna. Assinale a conduta mais adequada em relação à profilaxia neonatal da hepatite B.', options: ['Administrar imunoglobulina específica contra hepatite B e a primeira dose da vacina, ambas nas primeiras 12 a 24 horas de vida.', 'Administrar apenas a vacina de rotina do calendário vacinal, sem necessidade de imunoglobulina específica.', 'Aguardar resultado de carga viral materna antes de administrar qualquer profilaxia ao recém-nascido.', 'Contraindicar o aleitamento materno de forma absoluta, independente de qualquer profilaxia realizada no recém-nascido.'], correctIndex: 0, explanation: 'Recém-nascido de mãe HBsAg positiva deve receber imunoglobulina específica e a primeira dose da vacina contra hepatite B nas primeiras 12 a 24 horas de vida, reduzindo significativamente o risco de transmissão perinatal. Administrar apenas a vacina de rotina, sem a imunoglobulina específica, é esquema incompleto para essa situação de risco; aguardar a carga viral materna atrasa uma profilaxia tempo-dependente; o aleitamento materno não é contraindicado de forma absoluta quando a profilaxia neonatal adequada foi realizada.' },
  { id: 'cermam_gerado26_034', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Recém-nascido a termo, ao nascimento, apresenta defeito de parede abdominal lateral ao cordão umbilical, com alças intestinais exteriorizadas diretamente em contato com o líquido amniótico, sem membrana de revestimento, cordão umbilical inserido normalmente. Assinale o diagnóstico e uma característica que o diferencia de sua principal condição diferencial.', options: ['Gastrosquise; ao contrário do onfalocele, não possui membrana de revestimento cobrindo as alças exteriorizadas.', 'Onfalocele; apresenta as mesmas características de ausência de membrana de revestimento observadas na gastrosquise.', 'Hérnia umbilical congênita; exige o mesmo manejo cirúrgico de urgência da gastrosquise, sem qualquer diferença de conduta.', 'Extrofia vesical; não tem qualquer relação com defeitos de parede abdominal contendo alças intestinais.'], correctIndex: 0, explanation: 'A gastrosquise caracteriza-se por defeito de parede abdominal lateral ao cordão, com alças exteriorizadas sem membrana de revestimento, diferentemente do onfalocele, que ocorre na base do cordão e é revestido por membrana (peritônio e âmnio). Afirmar que o onfalocele também não tem membrana de revestimento inverte essa característica diferencial central; a hérnia umbilical congênita é revestida por pele e não exige manejo cirúrgico de urgência da mesma forma; a extrofia vesical é defeito distinto da parede abdominal inferior, sem relação com exteriorização de alças intestinais.' },
  { id: 'cermam_gerado26_035', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Homem de 28 anos, vítima de trauma torácico fechado em acidente automobilístico, com dispneia importante, ausculta com murmúrio vesicular abolido em hemitórax esquerdo e macicez à percussão, drenagem torácica inicial com débito de 1.400 mL de sangue, mantendo débito de 250 mL/h nas duas horas seguintes. Assinale a conduta mais adequada.', options: ['Toracotomia de urgência, dado o débito inicial elevado e a manutenção de débito importante pela drenagem.', 'Apenas observação clínica, sem toracotomia, independente do débito de sangue pela drenagem torácica.', 'Nova drenagem torácica adicional isolada, sem qualquer consideração de toracotomia.', 'Pericardiocentese de urgência, considerando tamponamento cardíaco como única hipótese diagnóstica.'], correctIndex: 0, explanation: 'Débito inicial elevado (acima de 1.000-1.500 mL) e manutenção de débito importante (acima de 200 mL/h) pela drenagem torácica são critérios clássicos de indicação de toracotomia de urgência no hemotórax maciço. Observação isolada sem toracotomia, diante desses critérios de débito, é perigosa; nova drenagem adicional isolada não controla uma fonte de sangramento que já preenche critério cirúrgico; a pericardiocentese é indicada para tamponamento cardíaco, quadro distinto do hemotórax maciço descrito, sem os achados típicos de tamponamento (turgência jugular, abafamento de bulhas, pulso paradoxal).' },
  { id: 'cermam_gerado26_036', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Mulher de 50 anos, com dor em hipocôndrio direito há 12 horas, febre de 38,6°C, Murphy positivo, ultrassonografia com parede vesicular espessada e cálculo impactado no colo. Assinale a conduta mais adequada.', options: ['Colecistectomia videolaparoscópica precoce, associada a antibioticoterapia.', 'Tratamento clínico exclusivo com antibiótico, sem cirurgia em nenhum momento.', 'Colecistectomia eletiva após 6 semanas de tratamento clínico exclusivo.', 'CPRE de urgência, independente de sinais de coledocolitíase.'], correctIndex: 0, explanation: 'Colecistite aguda tem indicação de colecistectomia precoce associada a antibioticoterapia. Tratamento clínico exclusivo expõe a risco de recorrência; postergar a cirurgia não é a abordagem preferida; CPRE não é rotina sem sinais de obstrução biliar.' },
  { id: 'cermam_gerado26_037', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Homem de 60 anos, tabagista, disfagia progressiva primeiro para sólidos e depois líquidos, perda ponderal importante, biópsia endoscópica confirmando carcinoma espinocelular em terço médio do esôfago. Assinale a conduta mais adequada antes de definir o tratamento.', options: ['Estadiamento com tomografia de tórax/abdome e ecoendoscopia, quando indicada.', 'Esofagectomia imediata, sem qualquer estadiamento prévio.', 'Radioterapia paliativa isolada, sem investigação estadiadora.', 'Quimioterapia isolada sem estadiamento prévio.'], correctIndex: 0, explanation: 'Após confirmação histológica, o estadiamento é essencial para definir a extensão e estratégia terapêutica. Esofagectomia sem estadiamento pode ser inadequada; radioterapia e quimioterapia isoladas sem estadiamento não definem adequadamente a estratégia.' },
  { id: 'cermam_gerado26_038', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Homem de 58 anos, com três cirurgias abdominais prévias, apresenta dor abdominal em cólica, distensão progressiva, parada de eliminação de gases e fezes há 2 dias, vômitos biliosos, radiografia de abdome com múltiplos níveis hidroaéreos em delgado. Assinale a conduta inicial mais apropriada.', options: ['Descompressão com sonda nasogástrica, hidratação venosa e observação clínica rigorosa, reservando cirurgia para sinais de estrangulamento ou falha do tratamento conservador.', 'Laparotomia de urgência obrigatória em todos os casos, independente da resposta ao tratamento conservador inicial.', 'Apenas laxante oral isolado, sem qualquer descompressão ou hidratação venosa.', 'Colonoscopia terapêutica de urgência, considerando obstrução colônica como única hipótese diagnóstica.'], correctIndex: 0, explanation: 'Obstrução intestinal por bridas (aderências) em paciente com cirurgias abdominais prévias é inicialmente tratada com descompressão nasogástrica, hidratação e observação rigorosa, reservando cirurgia para sinais de estrangulamento ou falha do tratamento conservador. Laparotomia obrigatória em todos os casos ignora a possibilidade de resolução conservadora nas obstruções por bridas sem sinais de estrangulamento; laxante oral isolado é contraindicado diante de obstrução mecânica com vômitos; colonoscopia terapêutica não é indicada para obstrução de delgado, sendo o quadro compatível com obstrução do intestino delgado, não do cólon.' },
  { id: 'cermam_gerado26_039', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Homem de 25 anos, vítima de trauma abdominal fechado em acidente esportivo, hipotenso a despeito de reposição volêmica inicial, tomografia prévia (antes da instabilização) evidenciando laceração esplênica extensa com hematoma perisplênico volumoso. Assinale a conduta mais adequada diante da instabilidade hemodinâmica atual.', options: ['Laparotomia de urgência com esplenectomia, dada a instabilidade hemodinâmica persistente.', 'Manejo não operatório exclusivo com observação seriada, independente da instabilidade hemodinâmica atual.', 'Embolização angiográfica isolada como única conduta, independente da instabilidade hemodinâmica.', 'Alta hospitalar com retorno ambulatorial em 7 dias, dado que o trauma esplênico tem resolução espontânea na maioria dos casos.'], correctIndex: 0, explanation: 'Instabilidade hemodinâmica persistente a despeito de reposição volêmica, em trauma esplênico com lesão extensa, indica laparotomia de urgência com esplenectomia. O manejo não operatório é reservado a pacientes estáveis ou que respondem à reposição volêmica, não ao paciente instável; a embolização isolada não controla adequadamente uma hemorragia ativa em paciente instável, sendo mais associada ao manejo não operatório de pacientes estáveis; alta hospitalar diante de instabilidade hemodinâmica é uma conduta perigosa e inadequada.' },
  { id: 'cermam_gerado26_040', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Homem de 50 anos, com febre, dor em hipocôndrio direito e hepatomegalia dolorosa há 5 dias, tomografia evidenciando coleção hepática única de 6 cm com paredes espessadas, leucocitose importante. Assinale a hipótese diagnóstica mais provável e a conduta.', options: ['Abscesso hepático piogênico; drenagem (percutânea ou cirúrgica) associada a antibioticoterapia de amplo espectro.', 'Cisto hidático hepático; punção percutânea isolada, sem qualquer antibioticoterapia ou consideração de albendazol.', 'Hemangioma hepático complicado; observação isolada, sem qualquer drenagem ou antibioticoterapia.', 'Metástase hepática única; biópsia isolada, sem qualquer conduta relacionada ao quadro infeccioso agudo.'], correctIndex: 0, explanation: 'Febre, dor em hipocôndrio direito, hepatomegalia dolorosa e coleção hepática com leucocitose são compatíveis com abscesso hepático piogênico, tratado com drenagem associada a antibioticoterapia de amplo espectro. O cisto hidático tem risco de reação anafilática à punção sem preparo adequado com albendazol, sendo abordagem distinta; hemangioma não cursa com esse quadro infeccioso agudo; metástase hepática não explica a leucocitose e o quadro febril agudo dessa forma, exigindo abordagem diferente do quadro infeccioso descrito.' },
  { id: 'cermam_gerado26_041', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Homem de 68 anos, com abaulamento inguinal direito conhecido há anos, procura atendimento por dor intensa e súbita, náuseas e impossibilidade de redução manual da massa, antes redutível. Assinale a conduta correta.', options: ['Correção cirúrgica de urgência, pela suspeita de encarceramento com risco de estrangulamento.', 'Tentativa vigorosa e repetida de redução manual, independente do tempo de evolução da dor.', 'Alta com anti-inflamatório e retorno ambulatorial eletivo.', 'Observação domiciliar até que a massa reduza espontaneamente.'], correctIndex: 0, explanation: 'Hérnia previamente redutível que se torna irredutível e dolorosa sugere encarceramento com risco de estrangulamento, exigindo correção cirúrgica de urgência. Tentativas vigorosas de redução podem reduzir alça já isquêmica; alta com anti-inflamatório ignora uma emergência cirúrgica; observação arrisca necrose intestinal.' },
  { id: 'cermam_gerado26_042', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Mulher de 62 anos, com massa palpável em quadrante superior externo da mama direita, mamografia com lesão espiculada BI-RADS 5. Assinale o próximo passo mais adequado antes de definir a estratégia terapêutica.', options: ['Biópsia percutânea (core biopsy) para confirmação histológica.', 'Mastectomia radical imediata, sem confirmação histológica prévia.', 'Observação clínica com nova mamografia em 12 meses.', 'Quimioterapia empírica, sem qualquer biópsia.'], correctIndex: 0, explanation: 'Mesmo com alta suspeição radiológica, a biópsia percutânea é necessária para confirmação histológica antes de definir a estratégia terapêutica. Mastectomia sem confirmação é desproporcional; observação por 12 meses é inadequada; quimioterapia empírica sem biópsia trataria uma doença ainda não confirmada.' },
  { id: 'cermam_gerado26_043', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Homem de 50 anos, com pancreatite aguda grave, evolui no quarto dia com necrose pancreática identificada em tomografia, sem sinais clínicos ou laboratoriais de infecção. Assinale a conduta mais apropriada nesse momento.', options: ['Manejo conservador com suporte clínico, sem indicação de intervenção sobre a necrose estéril.', 'Necrosectomia cirúrgica imediata, independente de sinais de infecção.', 'Antibioticoterapia profilática de rotina para necrose estéril.', 'Drenagem percutânea imediata, independente de sinais de infecção.'], correctIndex: 0, explanation: 'Necrose pancreática estéril, sem sinais de infecção, é manejada de forma conservadora. Necrosectomia imediata sem sinais de infecção é desproporcional; antibioticoterapia profilática de rotina não é recomendada; drenagem percutânea imediata sem sinais de infecção não é indicada.' },
  { id: 'cermam_gerado26_044', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Homem de 55 anos, com massa cervical anterior de crescimento progressivo, ultrassonografia de tireoide classificando o nódulo como alto risco (TI-RADS 5). Assinale a próxima etapa de investigação mais apropriada.', options: ['Punção aspirativa por agulha fina do nódulo, guiada por ultrassonografia.', 'Tireoidectomia total imediata, sem qualquer confirmação citológica prévia.', 'Observação clínica isolada, sem qualquer investigação adicional.', 'Cintilografia como único exame necessário, sem punção.'], correctIndex: 0, explanation: 'Nódulo de alto risco tem indicação de punção aspirativa guiada por imagem. Tireoidectomia sem confirmação citológica é desproporcional; observação isolada ignora características de alto risco; cintilografia não substitui a punção diante dessas características suspeitas.' },
  { id: 'cermam_gerado26_045', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Homem de 30 anos, vítima de ferimento penetrante abdominal por arma de fogo, instável hemodinamicamente. Assinale a conduta padrão, segundo os princípios de cirurgia de controle de danos.', options: ['Controle rápido de hemorragia e contaminação, adiando reconstruções definitivas para momento posterior.', 'Reconstrução anatômica completa e definitiva de todas as lesões na primeira intervenção.', 'Observação clínica isolada, sem intervenção cirúrgica imediata.', 'Anastomoses intestinais múltiplas complexas como prioridade sobre o controle hemorrágico.'], correctIndex: 0, explanation: 'A cirurgia de controle de danos prioriza o controle rápido de hemorragia e contaminação, adiando reconstruções definitivas. Reconstrução completa na primeira intervenção agrava a tríade letal; observação isolada é inadequada; anastomoses complexas antes do controle hemorrágico invertem a prioridade correta.' },
  { id: 'cermam_gerado26_046', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Homem de 45 anos, com massa testicular indolor de crescimento progressivo, ultrassonografia confirmando lesão sólida intratesticular. Assinale a conduta correta.', options: ['Orquiectomia inguinal radical, com dosagem prévia de marcadores tumorais.', 'Biópsia percutânea transescrotal da lesão como primeira etapa diagnóstica.', 'Observação clínica isolada por 6 meses.', 'Quimioterapia empírica isolada, sem qualquer avaliação cirúrgica.'], correctIndex: 0, explanation: 'Massa testicular sólida sugestiva de neoplasia tem indicação de orquiectomia inguinal radical, evitando biópsia transescrotal pelo risco de disseminação. Biópsia transescrotal não é conduta padrão; observação isolada atrasa o diagnóstico; quimioterapia empírica sem diagnóstico histológico não é conduta apropriada.' },
  { id: 'cermam_gerado26_047', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Gastroenterologia', text: 'Homem de 70 anos, com hematoquezia indolor de moderado volume, sem instabilidade hemodinâmica, colonoscopia prévia (há 2 anos) evidenciando múltiplos divertículos em cólon esquerdo, sem lesão neoplásica identificada. Assinale a conduta mais apropriada diante desse episódio de sangramento.', options: ['Estabilização clínica, investigação com colonoscopia (após preparo adequado) para identificar e eventualmente tratar o ponto de sangramento diverticular, reservando cirurgia para casos refratários.', 'Colectomia de urgência em todo episódio de hemorragia digestiva baixa por divertículos, independente da resposta ao tratamento clínico inicial.', 'Apenas observação isolada, sem qualquer investigação endoscópica, dado o antecedente já conhecido de divertículos.', 'Angiografia mesentérica isolada como único método diagnóstico e terapêutico válido, sem qualquer consideração de colonoscopia.'], correctIndex: 0, explanation: 'Hemorragia digestiva baixa por divertículos em paciente estável é conduzida com estabilização e colonoscopia para localizar e eventualmente tratar o ponto de sangramento, reservando cirurgia para casos refratários. Colectomia de urgência em todo episódio, sem tentativa de tratamento endoscópico ou resposta ao tratamento clínico, é desproporcional; observação isolada sem investigação ignora a necessidade de identificar e eventualmente tratar a origem do sangramento; a angiografia é opção em casos selecionados (sangramento ativo intenso ou colonoscopia inconclusiva), não substituindo a colonoscopia como abordagem inicial habitual.' },
  { id: 'cermam_gerado26_048', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Gastroenterologia', text: 'Mulher de 32 anos, com fadiga, icterícia intermitente e transaminases muito elevadas (TGO 480 U/L, TGP 520 U/L), FAN positivo em altos títulos, anti-músculo liso positivo, hipergamaglobulinemia importante, sem uso de medicamentos hepatotóxicos ou consumo relevante de álcool. Assinale o diagnóstico mais provável e a base do tratamento.', options: ['Hepatite autoimune tipo 1; corticoterapia, associada a azatioprina para manutenção da remissão.', 'Colangite biliar primária; ácido ursodesoxicólico isolado, sem necessidade de imunossupressão.', 'Hepatite viral aguda C; interferon peguilado isolado, sem necessidade de corticoide.', 'Doença hepática gordurosa não alcoólica; apenas mudança de estilo de vida, sem qualquer imunossupressão.'], correctIndex: 0, explanation: 'Transaminases muito elevadas com FAN e anti-músculo liso positivos e hipergamaglobulinemia são característicos da hepatite autoimune tipo 1, tratada com corticoterapia e azatioprina para manutenção. A colangite biliar primária cursa com padrão colestático (fosfatase alcalina predominante) e anticorpo antimitocôndria, não esse padrão de hepatite com autoanticorpos distintos; a hepatite C não explica esse perfil de autoanticorpos nem a hipergamaglobulinemia importante; a doença hepática gordurosa não cursa tipicamente com esse grau de elevação transaminásica e perfil autoimune.' },
  { id: 'cermam_gerado26_049', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Gastroenterologia', text: 'Homem de 62 anos, com hematêmese volumosa, cirrose hepática por álcool, PA 82/54 mmHg, endoscopia de urgência com varizes esofágicas sangrantes. Além da ressuscitação volêmica, assinale a conduta mais adequada.', options: ['Terlipressina intravenosa associada a ligadura elástica endoscópica e antibioticoterapia profilática.', 'Apenas ligadura endoscópica, sem terlipressina ou antibiótico.', 'Balão de Sengstaken-Blakemore como primeira medida, antes de qualquer endoscopia.', 'Betabloqueador intravenoso em altas doses como principal medida hemostática.'], correctIndex: 0, explanation: 'Sangramento por varizes esofágicas é tratado com terlipressina, ligadura endoscópica e antibioticoterapia profilática. Ligadura isolada sem terlipressina e antibiótico não segue o protocolo completo; o balão é medida de resgate temporário; betabloqueador intravenoso não é a principal medida hemostática aguda.' },
  { id: 'cermam_gerado26_050', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Gastroenterologia', text: 'Mulher de 30 anos, com diarreia crônica, distensão abdominal e anemia ferropriva, sorologia positiva para antitransglutaminase. Assinale o tratamento indicado.', options: ['Dieta isenta de glúten.', 'Corticoide isolado.', 'Antibiótico de amplo espectro.', 'Dieta isenta de lactose.'], correctIndex: 0, explanation: 'Anticorpos antitransglutaminase positivos confirmam doença celíaca, tratada com dieta isenta de glúten por toda a vida. Corticoide isolado não trata a causa autoimune; antibiótico não tem papel nessa enteropatia não infecciosa; dieta isenta de lactose trataria intolerância à lactose, condição distinta.' },
  { id: 'cermam_gerado26_051', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Infectologia', text: 'Homem de 35 anos, retorna de área endêmica com febre alta, mialgia intensa, exantema no 4º dia, dor abdominal intensa persistente e sangramento de mucosa. Assinale a classificação de gravidade e a conduta.', options: ['Dengue com sinais de alarme; internação para hidratação venosa e monitorização.', 'Dengue sem sinais de alarme; alta com hidratação oral apenas.', 'Febre amarela; vacinação imediata como tratamento.', 'Chikungunya; apenas analgesia, sem necessidade de internação.'], correctIndex: 0, explanation: 'Dor abdominal intensa e sangramento de mucosa são sinais de alarme na dengue, exigindo internação para hidratação venosa e monitorização. Classificar sem sinais de alarme ignora os sinais presentes; vacinação não trata febre amarela já instalada; chikungunya não costuma cursar com esses sinais.' },
  { id: 'cermam_gerado26_052', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Infectologia', text: 'Homem de 40 anos, com tosse produtiva há 4 semanas, febre vespertina, sudorese noturna, baciloscopia positiva para BAAR. Assinale o esquema terapêutico padrão sem tratamento prévio.', options: ['RIPE por 2 meses, seguido de rifampicina e isoniazida por 4 meses.', 'Isoniazida isolada por 6 meses.', 'Rifampicina isolada por 12 meses.', 'Etambutol e pirazinamida isolados por 6 meses.'], correctIndex: 0, explanation: 'O esquema básico é 2 meses de RIPE seguidos de 4 meses de rifampicina e isoniazida. Isoniazida isolada por 6 meses é esquema de infecção latente; rifampicina isolada e etambutol/pirazinamida isolados não constituem esquemas padrão adequados.' },
  { id: 'cermam_gerado26_053', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Infectologia', text: 'Homem de 30 anos, HIV positivo, CD4 de 90 células/mm³, com cefaleia progressiva e lesão com realce em anel em núcleos da base. Assinale o tratamento empírico inicial mais apropriado.', options: ['Sulfadiazina associada a pirimetamina e ácido folínico.', 'Ceftriaxona isolada.', 'Anfotericina B isolada, sem investigação de imagem.', 'Quimioterapia isolada, sem tratamento empírico prévio.'], correctIndex: 0, explanation: 'Lesão com realce em anel em núcleos da base em paciente com CD4 baixo é sugestiva de neurotoxoplasmose, tratada com sulfadiazina, pirimetamina e ácido folínico. Ceftriaxona cobre bactérias; anfotericina B é direcionada a fungos; quimioterapia seria voltada a linfoma primário do SNC.' },
  { id: 'cermam_gerado26_054', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Infectologia', text: 'Adolescente de 15 anos, contactante próximo de caso confirmado de doença meningocócica há 24 horas, assintomático. Assinale a conduta quanto à quimioprofilaxia.', options: ['Rifampicina por via oral, idealmente iniciada em até 48 horas do contato com o caso índice.', 'Nenhuma profilaxia é necessária, pois o adolescente está assintomático.', 'Vacinação isolada contra meningococo, sem necessidade de quimioprofilaxia antibiótica.', 'Antibioticoterapia intravenosa hospitalar, independente da ausência de sintomas.'], correctIndex: 0, explanation: 'Contactantes próximos devem receber rifampicina oral em até 48 horas do contato, mesmo assintomáticos. Não profilaxiar ignora o risco de transmissão; vacinação isolada não substitui a profilaxia; antibioticoterapia intravenosa hospitalar é desproporcional.' },
  { id: 'cermam_gerado26_055', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Endocrinologia', text: 'Mulher de 30 anos, com perda de peso, taquicardia, tremores finos, exoftalmia bilateral e bócio difuso, TSH suprimido e T4 livre elevado. Assinale o diagnóstico e o tratamento inicial.', options: ['Doença de Graves; tionamida antitireoidiana (como metimazol).', 'Tireoidite de Hashimoto; reposição de levotiroxina.', 'Bócio multinodular atóxico; observação clínica isolada, sem tratamento medicamentoso.', 'Adenoma hipofisário não funcionante; cirurgia transesfenoidal imediata.'], correctIndex: 0, explanation: 'Exoftalmia, bócio difuso e hipertireoidismo laboratorial confirmam doença de Graves, tratada com tionamida antitireoidiana. Hashimoto cursa com hipotireoidismo; bócio multinodular atóxico não cursa com hipertireoidismo florido; adenoma não funcionante não causa hipertireoidismo.' },
  { id: 'cermam_gerado26_056', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Endocrinologia', text: 'Homem de 50 anos, obeso, com poliúria, polidipsia, glicemia de jejum de 190 mg/dL em duas ocasiões. Assinale a alternativa correta sobre o diagnóstico de diabetes mellitus tipo 2.', options: ['Pode ser confirmado por glicemia de jejum igual ou superior a 126 mg/dL em duas ocasiões distintas.', 'Exige obrigatoriamente teste oral de tolerância à glicose em todos os casos.', 'Só pode ser diagnosticado na presença de cetoacidose diabética associada.', 'Depende exclusivamente da presença de anticorpos anti-ilhota positivos.'], correctIndex: 0, explanation: 'O diagnóstico pode ser confirmado por glicemia de jejum igual ou superior a 126 mg/dL em duas ocasiões distintas. O TOTG não é obrigatório em todos os casos; a cetoacidose não é pré-requisito diagnóstico do tipo 2; anticorpos anti-ilhota são marcadores do tipo 1.' },
  { id: 'cermam_gerado26_057', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Endocrinologia', text: 'Homem de 45 anos, com episódios paroxísticos de cefaleia intensa, sudorese profusa e palpitações, associados a picos hipertensivos (PA chegando a 220/130 mmHg durante as crises), com normalização parcial entre os episódios. Assinale o diagnóstico mais provável e o exame inicial mais indicado.', options: ['Feocromocitoma; dosagem de metanefrinas plasmáticas ou urinárias fracionadas.', 'Hipertireoidismo; dosagem isolada de TSH como exame confirmatório do quadro paroxístico.', 'Síndrome do pânico; eletrocardiograma isolado como exame inicial mais indicado.', 'Hiperaldosteronismo primário; dosagem isolada de potássio sérico como exame confirmatório.'], correctIndex: 0, explanation: 'Episódios paroxísticos de cefaleia, sudorese, palpitações e picos hipertensivos são a tríade clássica do feocromocitoma, investigado inicialmente com metanefrinas plasmáticas ou urinárias fracionadas. O hipertireoidismo não costuma cursar com picos hipertensivos paroxísticos tão marcados nem seria confirmado apenas por TSH isolado nesse contexto; a síndrome do pânico não explica os picos hipertensivos tão elevados e o ECG isolado não é o exame diagnóstico direcionado; o hiperaldosteronismo primário cursa com hipertensão mantida associada a hipocalemia, não com esse padrão paroxístico, e potássio isolado não é exame confirmatório.' },
  { id: 'cermam_gerado26_058', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Neurologia', text: 'Mulher de 27 anos, com episódios recorrentes de perda visual unilateral, parestesias e fraqueza em membros, ressonância magnética evidenciando lesões desmielinizantes disseminadas no espaço e no tempo. Assinale o diagnóstico mais provável.', options: ['Esclerose múltipla.', 'Acidente vascular cerebral de repetição.', 'Miastenia gravis.', 'Síndrome de Guillain-Barré.'], correctIndex: 0, explanation: 'Lesões desmielinizantes disseminadas no espaço e no tempo são o critério diagnóstico central da esclerose múltipla. AVC de repetição teria lesões vasculares; miastenia gravis não apresenta lesões de substância branca; Guillain-Barré cursa com fraqueza ascendente aguda.' },
  { id: 'cermam_gerado26_059', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Neurologia', text: 'Homem de 70 anos, com bradicinesia progressiva, rigidez em roda denteada, tremor de repouso assimétrico e marcha com passos curtos. Assinale o diagnóstico e a base do tratamento inicial.', options: ['Doença de Parkinson idiopática; levodopa associada a carbidopa, conforme impacto funcional.', 'Tremor essencial; propranolol como tratamento de primeira linha para o quadro descrito.', 'Paralisia supranuclear progressiva; levodopa em altas doses, com excelente resposta esperada.', 'Hidrocefalia de pressão normal; apenas derivação ventriculoperitoneal, sem tratamento farmacológico.'], correctIndex: 0, explanation: 'Bradicinesia, rigidez, tremor de repouso assimétrico e marcha característica são a tríade da doença de Parkinson, tratada com levodopa/carbidopa. Tremor essencial é tipicamente de ação; a paralisia supranuclear tem resposta pobre à levodopa; a hidrocefalia de pressão normal cursaria com a tríade de Hakim.' },
  { id: 'cermam_gerado26_060', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Nefrologia', text: 'Homem de 45 anos, com edema periorbitário e de membros inferiores, proteinúria de 5 g/24h, hipoalbuminemia e hiperlipidemia, sem hematúria significativa. Assinale o diagnóstico sindrômico e a principal complicação trombótica associada.', options: ['Síndrome nefrótica; trombose de veia renal.', 'Síndrome nefrítica; glomerulonefrite rapidamente progressiva.', 'Insuficiência renal aguda pré-renal; necrose tubular aguda.', 'Síndrome hemolítico-urêmica; trombocitopenia isolada.'], correctIndex: 0, explanation: 'Proteinúria maciça, hipoalbuminemia, edema e hiperlipidemia caracterizam síndrome nefrótica, cuja complicação trombótica clássica é a trombose de veia renal. A síndrome nefrítica cursa com hematúria e hipertensão proeminentes; a insuficiência renal pré-renal não explica a proteinúria maciça; a síndrome hemolítico-urêmica cursa com anemia hemolítica microangiopática.' },
  { id: 'cermam_gerado26_061', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Nefrologia', text: 'Homem de 60 anos, em hemodiálise crônica, ECG pré-diálise com ondas T apiculadas e QRS alargado, potássio sérico de 7,3 mEq/L. Assinale a conduta imediata prioritária.', options: ['Gluconato de cálcio intravenoso, seguido de medidas para reduzir o potássio sérico.', 'Apenas aumentar a dose de resina de troca iônica oral, sem qualquer medida imediata.', 'Aguardar a próxima sessão de diálise agendada, sem qualquer intervenção imediata.', 'Reposição de potássio oral, para investigar pseudo-hipercalemia.'], correctIndex: 0, explanation: 'Hipercalemia grave com alterações eletrocardiográficas exige gluconato de cálcio intravenoso imediato, seguido de medidas para reduzir o potássio. Resina oral tem ação lenta; aguardar a próxima diálise é perigoso; repor potássio pioraria o quadro.' },
  { id: 'cermam_gerado26_062', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Cardiologia', text: 'Homem de 62 anos, com dor torácica típica em repouso, eletrocardiograma com supradesnivelamento de ST em parede inferior. Assinale a conduta imediata prioritária.', options: ['Reperfusão coronariana urgente, por angioplastia primária ou trombólise.', 'Teste ergométrico imediato para confirmação diagnóstica antes de qualquer intervenção.', 'Alta hospitalar com anti-inflamatório, dado o padrão eletrocardiográfico apenas inferior.', 'Apenas observação clínica seriada por 72 horas, sem reperfusão.'], correctIndex: 0, explanation: 'Supradesnivelamento de ST com dor torácica típica caracteriza infarto agudo do miocárdio com supra de ST, exigindo reperfusão urgente. Teste ergométrico é contraindicado na fase aguda; alta com anti-inflamatório ignora uma emergência cardiovascular; observação seriada sem reperfusão aumenta a área de necrose.' },
  { id: 'cermam_gerado26_063', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Cardiologia', text: 'Homem de 55 anos, com palpitações e eletrocardiograma evidenciando ritmo irregularmente irregular, ausência de ondas P e resposta ventricular de 130 bpm, CHA2DS2-VASc de 3. Assinale a conduta mais adequada.', options: ['Anticoagulação oral, dado o escore de risco tromboembólico elevado.', 'Nenhuma anticoagulação, dado que a frequência cardíaca está controlada.', 'Cardioversão elétrica imediata, sem qualquer avaliação do risco tromboembólico prévio.', 'Apenas controle de frequência, sem qualquer avaliação de anticoagulação.'], correctIndex: 0, explanation: 'CHA2DS2-VASc de 3 indica risco tromboembólico significativo, justificando anticoagulação oral. A frequência controlada não elimina o risco tromboembólico; cardioversão sem avaliação do risco e sem anticoagulação prévia expõe a risco de embolização; controle de frequência isolado ignora um componente essencial do manejo.' },
  { id: 'cermam_gerado26_064', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Reumatologia', text: 'Mulher de 25 anos, com eritema malar poupando sulco nasolabial, fotossensibilidade, artrite não erosiva de pequenas articulações, proteinúria e FAN positivo em altos títulos, anti-DNA de dupla hélice positivo. Assinale o diagnóstico mais provável.', options: ['Lúpus eritematoso sistêmico.', 'Dermatomiosite.', 'Esclerose sistêmica.', 'Artrite reumatoide.'], correctIndex: 0, explanation: 'Eritema malar poupando sulco nasolabial, fotossensibilidade, artrite não erosiva, proteinúria e anti-DNA positivo confirmam lúpus eritematoso sistêmico. A dermatomiosite cursa com heliotropo e Gottron; a esclerose sistêmica cursa com espessamento cutâneo; a artrite reumatoide cursa com artrite erosiva simétrica.' },
  { id: 'cermam_gerado26_065', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Reumatologia', text: 'Homem de 68 anos, com cefaleia temporal, claudicação mandibular e VHS muito elevado. Assinale a principal complicação a ser prevenida com tratamento imediato.', options: ['Cegueira por neuropatia óptica isquêmica.', 'Insuficiência renal aguda.', 'Meningite bacteriana.', 'Trombose venosa profunda.'], correctIndex: 0, explanation: 'Cefaleia temporal e claudicação mandibular sugerem arterite de células gigantes; o corticoide deve ser iniciado prontamente para prevenir cegueira irreversível. As demais complicações não têm relação fisiopatológica direta ou não são a complicação central a prevenir.' },
  { id: 'cermam_gerado26_066', banca: 'CERMAM', cycle: 'Internato', subject: 'Urgência e Emergência', text: 'Homem de 30 anos, trazido ao pronto-socorro com rebaixamento do nível de consciência, frequência respiratória de 6 irpm, miose puntiforme bilateral, encontrado ao lado de cartelas de medicamentos opioides vazias. Assinale a conduta imediata prioritária.', options: ['Naloxona intravenosa ou intramuscular, associada a suporte ventilatório conforme necessidade.', 'Flumazenil intravenoso isolado, sem qualquer suporte ventilatório associado.', 'Indução de vômito para eliminar o medicamento ainda não absorvido.', 'Observação clínica isolada por 6 horas, sem qualquer antídoto ou suporte ventilatório.'], correctIndex: 0, explanation: 'Depressão respiratória com miose puntiforme e história de ingestão de opioides indica intoxicação opioide, tratada com naloxona associada a suporte ventilatório conforme a gravidade. Flumazenil é antídoto para benzodiazepínicos, não opioides; induzir vômito é perigoso diante de rebaixamento do nível de consciência, pelo risco de aspiração; observação isolada sem antídoto nem suporte ventilatório é perigosa diante de depressão respiratória grave.' },
  { id: 'cermam_gerado26_067', banca: 'CERMAM', cycle: 'Internato', subject: 'Urgência e Emergência', text: 'Mulher de 24 anos, epiléptica conhecida, apresenta crise tônico-clônica generalizada contínua há 8 minutos, sem recuperação da consciência entre os movimentos. Já foi administrada uma dose de benzodiazepínico há 3 minutos, sem resposta. Assinale a conduta mais adequada nesse momento.', options: ['Administrar fenitoína (ou outra droga antiepiléptica de segunda linha) intravenosa, mantendo suporte de via aérea e monitorização.', 'Repetir apenas benzodiazepínico indefinidamente, sem considerar droga de segunda linha.', 'Aguardar mais 15 minutos de observação antes de qualquer nova medicação, dado que já foi administrado benzodiazepínico.', 'Iniciar anestesia geral com indução para intubação como primeira medida, sem qualquer tentativa de droga antiepiléptica de segunda linha.'], correctIndex: 0, explanation: 'Estado de mal epiléptico refratário à primeira dose de benzodiazepínico exige progressão para droga antiepiléptica de segunda linha (como fenitoína), mantendo suporte de via aérea. Repetir apenas benzodiazepínico indefinidamente sem escalonar o tratamento atrasa o controle da crise; aguardar mais 15 minutos sem nova conduta prolonga desnecessariamente um estado de mal já estabelecido; anestesia geral é reservada a casos refratários às drogas de segunda linha, não sendo a primeira medida nesse momento.' },
  { id: 'cermam_gerado26_068', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Pneumologia', text: 'Mulher de 68 anos, ex-tabagista, com DPOC, piora da dispneia habitual, aumento do volume e purulência do escarro há 3 dias, sem febre. Segundo os critérios de Anthonisen, assinale a classificação e a conduta.', options: ['Exacerbação tipo II (moderada); antibioticoterapia associada a broncodilatador e corticoide sistêmico.', 'Exacerbação tipo I (leve); sem necessidade de antibioticoterapia em nenhuma circunstância.', 'Exacerbação tipo III (grave); indicação obrigatória de ventilação mecânica invasiva.', 'Classificação não aplicável, pois Anthonisen é usado apenas em asma.'], correctIndex: 0, explanation: 'Dois dos três critérios de Anthonisen presentes caracterizam exacerbação tipo II, tratada com antibioticoterapia, broncodilatador e corticoide sistêmico. As demais classificações subestimam ou superestimam a gravidade descrita; Anthonisen é específico para DPOC, não asma.' },
  { id: 'cermam_gerado26_069', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Hematologia', text: 'Homem de 60 anos, com fadiga, dor óssea lombar, anemia normocítica, insuficiência renal e hipercalcemia, eletroforese de proteínas com pico monoclonal. Assinale o diagnóstico mais provável.', options: ['Mieloma múltiplo.', 'Leucemia mieloide aguda.', 'Linfoma de Hodgkin.', 'Policitemia vera.'], correctIndex: 0, explanation: 'Dor óssea, anemia, insuficiência renal, hipercalcemia e componente monoclonal formam a tétrade clássica do mieloma múltiplo. A leucemia mieloide aguda cursaria com pancitopenia; o linfoma de Hodgkin cursa com linfadenopatia; a policitemia vera cursa com poliglobulia.' },
  { id: 'cermam_gerado26_070', banca: 'CERMAM', cycle: 'Internato', subject: 'Neonatologia', text: 'Recém-nascido, 28 semanas, peso de 1000g, com desconforto respiratório progressivo desde os primeiros minutos de vida, radiografia de tórax com infiltrado reticulogranular difuso. Assinale a conduta recomendada.', options: ['Suporte ventilatório (CPAP nasal ou ventilação mecânica conforme gravidade) e surfactante exógeno, se indicado.', 'Antibioticoterapia isolada, sem qualquer suporte ventilatório.', 'Observação isolada, sem qualquer intervenção respiratória.', 'Apenas oxigênio em cateter nasal de baixo fluxo, independente da gravidade do desconforto.'], correctIndex: 0, explanation: 'O quadro é compatível com síndrome do desconforto respiratório do recém-nascido pré-termo, tratado com suporte ventilatório adequado e surfactante exógeno quando indicado. Antibioticoterapia isolada não trata a causa primária; observação isolada é perigosa; oxigênio em baixo fluxo isolado pode ser insuficiente.' },
  { id: 'cermam_gerado26_071', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Urologia', text: 'Homem de 68 anos, com diminuição do jato urinário, noctúria e esvaziamento incompleto há vários meses, PSA de 2,0 ng/mL, próstata aumentada e de consistência elástica ao toque retal, sem nódulos. Assinale a hipótese diagnóstica e a conduta inicial.', options: ['Hiperplasia prostática benigna; alfabloqueador para alívio sintomático inicial.', 'Câncer de próstata; biópsia prostática imediata, independente do PSA e do toque normal.', 'Prostatite bacteriana aguda; antibioticoterapia isolada, sem qualquer outro exame.', 'Estenose uretral; dilatação uretral de urgência, sem avaliação prévia.'], correctIndex: 0, explanation: 'Sintomas obstrutivos com PSA normal e próstata elástica, sem nódulos suspeitos, são compatíveis com hiperplasia prostática benigna, tratada com alfabloqueador. Biópsia imediata não é indicada com PSA normal e toque sem nódulo; prostatite bacteriana aguda cursaria com febre; estenose uretral não é a hipótese mais provável.' },
  { id: 'cermam_gerado26_072', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Ortopedia', text: 'Homem de 28 anos, vítima de acidente de moto, apresenta fratura exposta de tíbia com ferida de 3 cm, contaminação moderada e lesão de partes moles limitada, sem comprometimento vascular. Segundo a classificação de Gustilo-Anderson, assinale o grau da lesão e a conduta antibiótica inicial.', options: ['Grau II; cefalosporina de primeira geração como antibioticoprofilaxia inicial, associada ao desbridamento cirúrgico.', 'Grau I; associação obrigatória de aminoglicosídeo à cefalosporina, independente do grau da lesão.', 'Grau IIIC; amputação primária como conduta obrigatória, independente da avaliação vascular detalhada.', 'Grau IIIB; observação isolada, sem antibioticoprofilaxia ou desbridamento cirúrgico.'], correctIndex: 0, explanation: 'Ferida de até 1 cm caracterizaria grau I; entre 1 e 10 cm com contaminação moderada e sem lesão extensa de partes moles caracteriza o grau II, tratado com cefalosporina de primeira geração e desbridamento cirúrgico. O grau I exigiria antibioticoprofilaxia mais simples, sem associação obrigatória de aminoglicosídeo; o grau IIIC envolve lesão vascular exigindo reparo, ausente no caso, não indicando amputação primária obrigatória sem avaliação detalhada; o grau IIIB envolve lesão extensa de partes moles com exposição óssea significativa, exigindo antibioticoprofilaxia e desbridamento, não observação isolada.' },
  { id: 'cermam_gerado26_073', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'Homem de 62 anos, tabagista, com dispneia progressiva e baqueteamento digital, tomografia de tórax mostrando padrão reticular subpleural com faveolamento em bases. Assinale o diagnóstico mais provável.', options: ['Fibrose pulmonar idiopática.', 'Sarcoidose pulmonar.', 'Pneumonia em organização criptogênica.', 'Histiocitose pulmonar de células de Langerhans.'], correctIndex: 0, explanation: 'Faveolamento subpleural em bases com baqueteamento digital é o padrão radiológico clássico da fibrose pulmonar idiopática. A sarcoidose cursa com adenopatia hilar/mediastinal; a POC apresenta consolidações migratórias; a histiocitose de Langerhans acomete campos superiores.' },
  { id: 'cermam_gerado26_074', banca: 'CERMAM', cycle: 'Internato', subject: 'Cirurgia Vascular', text: 'Mulher de 52 anos, pós-operatório de cirurgia ortopédica há 5 dias, apresenta edema unilateral de membro inferior esquerdo, dor à palpação da panturrilha e empastamento muscular, sem sinais de insuficiência arterial associada. Assinale a hipótese diagnóstica mais provável e a conduta.', options: ['Trombose venosa profunda; anticoagulação, com confirmação diagnóstica por ultrassonografia com Doppler venoso.', 'Insuficiência arterial aguda; heparina isolada, sem investigação por Doppler venoso.', 'Celulite isolada; apenas antibioticoterapia, sem investigação de trombose venosa.', 'Linfedema primário; compressão elástica isolada, sem qualquer investigação de trombose.'], correctIndex: 0, explanation: 'Edema unilateral com dor à palpação da panturrilha em paciente com fator de risco (pós-operatório recente) sugere trombose venosa profunda, confirmada por Doppler venoso e tratada com anticoagulação. Insuficiência arterial aguda cursaria com dor isquêmica, palidez e ausência de pulsos, não esse quadro de edema; celulite isolada não explica adequadamente o quadro sem investigar a trombose concomitante; linfedema primário teria evolução mais crônica, não aguda dessa forma.' },
  { id: 'cermam_gerado26_075', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Psiquiatria', text: 'Homem de 25 anos, com pensamentos intrusivos recorrentes sobre contaminação e rituais de lavagem das mãos por horas ao dia, reconhecendo o comportamento como excessivo. Assinale a classe medicamentosa de primeira linha.', options: ['Inibidor seletivo da recaptação de serotonina, em doses geralmente mais altas que na depressão.', 'Antipsicótico isolado.', 'Benzodiazepínico isolado como tratamento de manutenção.', 'Estabilizador de humor isolado, sem associação com ISRS.'], correctIndex: 0, explanation: 'No transtorno obsessivo-compulsivo, os ISRS são a primeira linha farmacológica, geralmente em doses mais altas que na depressão. Antipsicótico isolado não é primeira linha; benzodiazepínico isolado traz risco de dependência; estabilizador de humor isolado não é a classe indicada.' },
  { id: 'cermam_gerado26_076', banca: 'CERMAM', cycle: 'Ciclo Básico', subject: 'Epidemiologia', text: 'Em um estudo sobre tabagismo e câncer de pulmão, pesquisadores identificam que fumantes também tendem a ter maior consumo de álcool, e o consumo de álcool está independentemente associado a maior risco de alguns tipos de câncer. Ao não considerar o consumo de álcool na análise, os pesquisadores correm o risco de superestimar a associação entre tabagismo e câncer de pulmão devido a qual fenômeno?', options: ['Viés de confusão (confounding), pelo álcool ser fator associado tanto à exposição quanto a desfechos relacionados.', 'Viés de aferição (information bias), relacionado à forma de medir a exposição ao tabaco.', 'Viés de seleção, relacionado à forma como os participantes foram incluídos no estudo.', 'Viés de publicação, relacionado à maior probabilidade de publicação de resultados positivos.'], correctIndex: 0, explanation: 'O álcool, associado tanto ao tabagismo (exposição) quanto a desfechos oncológicos, se não controlado na análise, configura viés de confusão, distorcendo a associação real entre tabagismo e câncer de pulmão. O viés de aferição relaciona-se à forma diferencial de medir a exposição, não à presença de uma terceira variável associada; o viés de seleção relaciona-se à forma de inclusão dos participantes, não a essa situação de confundimento; o viés de publicação refere-se à probabilidade de publicação dos estudos, não a esse fenômeno analítico dentro de um mesmo estudo.' },
  { id: 'cermam_gerado26_077', banca: 'CERMAM', cycle: 'Ciclo Básico', subject: 'Epidemiologia', text: 'Um teste rápido para uma doença de baixa prevalência populacional (2%) apresenta sensibilidade de 95% e especificidade de 90%. Assinale a alternativa correta sobre o valor preditivo positivo desse teste nessa população.', options: ['Será relativamente baixo, apesar da boa sensibilidade e especificidade, devido à baixa prevalência da doença.', 'Será sempre igual à sensibilidade do teste, independentemente da prevalência.', 'Será de 95%, idêntico ao valor da sensibilidade informada.', 'Não pode ser calculado sem o número absoluto de pacientes testados.'], correctIndex: 0, explanation: 'Em população de baixa prevalência, mesmo testes com boa sensibilidade e especificidade tendem a apresentar valor preditivo positivo relativamente baixo, pois a proporção de falsos-positivos se torna proporcionalmente maior entre os poucos verdadeiros-positivos. O valor preditivo positivo não é igual à sensibilidade, sendo dependente da prevalência; não é de 95%, valor da sensibilidade, mas sim inferior devido à baixa prevalência; pode ser calculado com a prevalência e os valores de sensibilidade/especificidade informados, sem necessidade do número absoluto de pacientes testados.' },
  { id: 'cermam_gerado26_078', banca: 'CERMAM', cycle: 'Ciclo Básico', subject: 'Epidemiologia', text: 'Em relação à notificação compulsória de doenças no Brasil, assinale a alternativa incorreta.', options: ['Doenças de notificação compulsória imediata podem aguardar até 30 dias para serem comunicadas.', 'A notificação compulsória é obrigação de todo profissional de saúde e de serviços de saúde, públicos ou privados.', 'A lista nacional de doenças de notificação compulsória é definida por portaria do Ministério da Saúde.', 'Algumas doenças exigem notificação em até 24 horas, dado seu potencial de disseminação.'], correctIndex: 0, explanation: 'É incorreto afirmar que doenças de notificação imediata podem aguardar 30 dias, pois exigem comunicação em prazo muito mais curto. As demais afirmações são corretas quanto à obrigatoriedade, à definição por portaria e ao prazo de 24 horas para doenças de notificação imediata.' },
  { id: 'cermam_gerado26_079', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação aos princípios doutrinários do Sistema Único de Saúde, a universalidade é definida como o princípio que estabelece:', options: ['O direito de acesso aos serviços de saúde a todos os cidadãos, independentemente de renda, contribuição prévia ou qualquer outra condição.', 'O acesso restrito aos serviços de saúde apenas a trabalhadores formais contribuintes da previdência social.', 'A necessidade de pagamento direto pelo usuário como pré-requisito de acesso aos serviços de saúde.', 'A oferta de serviços de saúde exclusivamente pelo setor privado, sem qualquer participação estatal direta.'], correctIndex: 0, explanation: 'A universalidade estabelece o direito de acesso aos serviços de saúde a todos os cidadãos, independentemente de renda ou contribuição prévia, sendo um dos pilares fundamentais do SUS. Restringir o acesso a trabalhadores formais contribuintes descreve modelo de seguro social (Bismarck), não o princípio da universalidade do SUS; exigir pagamento direto contraria esse princípio de acesso universal e gratuito; a oferta exclusivamente privada contraria a própria natureza pública e universal do sistema.' },
  { id: 'cermam_gerado26_080', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação ao território adscrito na Estratégia Saúde da Família, assinale a alternativa correta.', options: ['Refere-se à área geográfica delimitada com população definida, sob responsabilidade de uma equipe de saúde.', 'Refere-se exclusivamente aos limites administrativos municipais.', 'Refere-se à área de atuação restrita a hospitais terciários e quaternários.', 'É aplicável exclusivamente a áreas rurais.'], correctIndex: 0, explanation: 'O território adscrito refere-se à área geográfica delimitada com população definida, sob responsabilidade de uma equipe de saúde da família. Não se limita aos limites administrativos municipais; não se refere à atuação de hospitais terciários; é aplicável a contextos urbanos e rurais.' },
  { id: 'cermam_gerado26_081', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação à clínica ampliada como abordagem preconizada na atenção primária à saúde, assinale a alternativa correta.', options: ['Busca integrar o olhar biomédico tradicional a uma compreensão mais ampla do sujeito, considerando aspectos subjetivos, sociais e contextuais no processo de cuidado.', 'Restringe-se exclusivamente à ampliação do número de especialistas disponíveis em uma unidade de saúde.', 'Significa a ampliação do horário de funcionamento da unidade básica de saúde, sem relação com o processo clínico em si.', 'Aplica-se exclusivamente a pacientes com doenças crônicas, sem relação com atendimentos agudos.'], correctIndex: 0, explanation: 'A clínica ampliada integra o olhar biomédico a uma compreensão mais ampla do sujeito, considerando aspectos subjetivos, sociais e contextuais no cuidado. Não se restringe à ampliação do número de especialistas disponíveis; não se refere à ampliação do horário de funcionamento da unidade, sendo um conceito de abordagem clínica, não de gestão de horários; não é exclusiva de doenças crônicas, aplicando-se também a atendimentos agudos.' },
  { id: 'cermam_gerado26_082', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação às atribuições do Agente Comunitário de Saúde (ACS) na Estratégia Saúde da Família, assinale a alternativa correta.', options: ['Realiza visitas domiciliares regulares em seu microárea adscrita, atuando como elo entre a comunidade e a equipe de saúde, identificando situações de risco e necessidades de saúde.', 'Tem como atribuição exclusiva a administração de medicamentos injetáveis prescritos pelo médico da equipe.', 'Deve residir obrigatoriamente fora da comunidade em que atua, para preservar a imparcialidade do vínculo profissional.', 'Substitui integralmente a necessidade de consultas médicas ou de enfermagem para os usuários de sua microárea.'], correctIndex: 0, explanation: 'O ACS realiza visitas domiciliares regulares em sua microárea, atuando como elo entre comunidade e equipe, identificando riscos e necessidades. Administrar medicamentos injetáveis não é atribuição do ACS, sendo função de enfermagem; o ACS deve residir na comunidade em que atua, sendo esse vínculo territorial parte essencial de sua função; não substitui as consultas médicas ou de enfermagem, atuando de forma complementar à equipe.' },
  { id: 'cermam_gerado26_083', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação ao método clínico centrado na pessoa, assinale a alternativa correta.', options: ['Busca compreender a doença e também a experiência de adoecimento vivida pelo paciente, considerando contexto familiar e social.', 'Prioriza exclusivamente o diagnóstico biomédico, sem espaço para expectativas do paciente.', 'Restringe a decisão terapêutica exclusivamente ao médico, sem participação do paciente.', 'É aplicável apenas em consultas de longa duração, nunca em atendimentos breves.'], correctIndex: 0, explanation: 'O método clínico centrado na pessoa busca compreender a doença e a experiência de adoecimento, considerando o contexto familiar e social. Priorizar exclusivamente o diagnóstico biomédico contraria a essência do método; restringir a decisão exclusivamente ao médico contraria o princípio de decisão compartilhada.' },
  { id: 'cermam_gerado26_084', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação à Rede de Atenção Psicossocial e ao papel do CAPS, assinale a alternativa correta.', options: ['Atua na articulação do cuidado em saúde mental de base territorial e comunitária, com construção de projeto terapêutico singular.', 'Tem como estratégia central a internação psiquiátrica prolongada em hospital especializado.', 'Restringe-se ao atendimento de urgências psiquiátricas agudas, sem acompanhamento longitudinal.', 'É destinado exclusivamente a pacientes com dependência química.'], correctIndex: 0, explanation: 'O CAPS atua na articulação do cuidado em saúde mental de base territorial e comunitária. A Reforma Psiquiátrica preconiza a substituição do modelo hospitalocêntrico; o CAPS realiza acompanhamento longitudinal; atende diversas condições de saúde mental, não exclusivamente dependência química.' },
  { id: 'cermam_gerado26_085', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação aos determinantes sociais da saúde, assinale a alternativa correta.', options: ['Incluem condições de moradia, renda, escolaridade e acesso a saneamento básico, interagindo com determinantes biológicos.', 'Atuam de forma completamente independente dos determinantes biológicos.', 'Não têm qualquer relação com políticas intersetoriais de enfrentamento.', 'Se restringem exclusivamente a fatores genéticos individuais.'], correctIndex: 0, explanation: 'Os determinantes sociais incluem moradia, renda, escolaridade e saneamento, interagindo com determinantes biológicos. Afirmar independência completa ignora essa interação; políticas intersetoriais são resposta ao enfrentamento de determinantes sociais desfavoráveis; não se restringem a fatores genéticos.' },
  { id: 'cermam_gerado26_086', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação à hierarquização da rede de atenção à saúde no SUS, assinale a alternativa correta.', options: ['Organiza os serviços por níveis crescentes de complexidade, com fluxos de referência e contrarreferência entre eles.', 'Concentra todo o atendimento exclusivamente em hospitais terciários, independentemente da complexidade do caso.', 'Elimina completamente a atenção primária à saúde do sistema.', 'Restringe o acesso da população apenas aos serviços privados conveniados.'], correctIndex: 0, explanation: 'A hierarquização organiza os serviços por níveis crescentes de complexidade, com fluxos de referência e contrarreferência. Concentrar tudo em hospitais terciários contraria essa lógica; a atenção primária é a porta de entrada preferencial; o SUS não se restringe a serviços privados conveniados.' },
  { id: 'cermam_gerado26_087', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação ao apoio matricial (matriciamento) prestado pelo NASF às equipes de Saúde da Família, assinale a alternativa correta.', options: ['Consiste em arranjo organizacional que oferece suporte técnico-pedagógico e assistencial às equipes de referência, sem substituir o vínculo do usuário com sua equipe de saúde da família.', 'Implica a transferência definitiva do cuidado do usuário da equipe de saúde da família para o especialista do NASF.', 'Restringe-se ao atendimento individual direto de todos os usuários encaminhados, sem qualquer discussão de caso.', 'É aplicável exclusivamente a casos de saúde mental, sem relação com outras áreas de cuidado.'], correctIndex: 0, explanation: 'O matriciamento oferece suporte técnico-pedagógico e assistencial às equipes de referência, sem substituir o vínculo do usuário com sua equipe. Não implica transferência definitiva do cuidado; não se restringe ao atendimento individual direto; não é exclusivo de saúde mental.' },
  { id: 'cermam_gerado26_088', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação à Caderneta de Saúde da Criança e ao acompanhamento do crescimento e desenvolvimento, assinale a alternativa correta.', options: ['Permite o registro sistemático de marcos de desenvolvimento, curvas de crescimento e calendário vacinal, facilitando a detecção precoce de desvios.', 'Destina-se exclusivamente ao registro de intercorrências agudas, sem relação com desenvolvimento neuropsicomotor.', 'Não deve ser utilizada por profissionais de nível médio, sendo exclusiva do médico pediatra.', 'É aplicável apenas até os 12 meses de vida, sem uso posterior.'], correctIndex: 0, explanation: 'A Caderneta permite registro sistemático de marcos de desenvolvimento, curvas de crescimento e vacinação, facilitando a detecção precoce de desvios. Não se destina exclusivamente a intercorrências agudas; pode ser utilizada por toda a equipe multiprofissional; é utilizada além dos 12 meses.' },
  { id: 'cermam_gerado26_089', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação à Rede de Atenção às Urgências e Emergências (RUE) do SUS, assinale a alternativa correta.', options: ['Organiza-se de forma articulada entre atenção básica, SAMU, unidades de pronto atendimento e hospitais, buscando garantir acesso ágil e resolutivo às situações de urgência.', 'Restringe-se exclusivamente ao atendimento pré-hospitalar móvel (SAMU), sem articulação com outros pontos da rede.', 'Não estabelece qualquer fluxo de referência entre os diferentes níveis de atenção envolvidos no atendimento de urgência.', 'É aplicável exclusivamente a grandes centros urbanos, sem previsão de organização em municípios de menor porte.'], correctIndex: 0, explanation: 'A RUE organiza-se de forma articulada entre atenção básica, SAMU, UPA e hospitais, buscando acesso ágil e resolutivo às urgências. Não se restringe ao SAMU isoladamente, envolvendo múltiplos pontos de atenção; estabelece sim fluxos de referência entre os níveis de atenção; é aplicável a municípios de diferentes portes, com organização adaptada à realidade regional.' },
  { id: 'cermam_gerado26_090', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação à vigilância epidemiológica ativa e passiva, assinale a alternativa correta.', options: ['A vigilância ativa envolve busca proativa de casos pela equipe de saúde (por exemplo, busca ativa domiciliar), enquanto a passiva depende da notificação espontânea pelos serviços de saúde.', 'A vigilância ativa depende exclusivamente da notificação espontânea realizada pelos profissionais de saúde, sem qualquer busca proativa.', 'A vigilância passiva é sempre mais sensível para detecção de casos do que a vigilância ativa.', 'Não há qualquer diferença metodológica entre vigilância ativa e passiva em saúde pública.'], correctIndex: 0, explanation: 'A vigilância ativa envolve busca proativa de casos pela equipe (busca ativa domiciliar, por exemplo), enquanto a passiva depende da notificação espontânea dos serviços. Descrever a vigilância ativa como dependente exclusivamente de notificação espontânea inverte essa definição, que é característica da vigilância passiva; a vigilância ativa costuma ser mais sensível para detecção de casos do que a passiva, não o contrário; há diferença metodológica relevante entre ambas.' },
  { id: 'cermam_gerado26_091', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação aos atributos da Atenção Primária à Saúde, assinale a alternativa correta sobre a coordenação do cuidado.', options: ['Refere-se à capacidade da atenção primária de organizar e integrar o cuidado do usuário entre diferentes níveis e pontos da rede de atenção, evitando fragmentação.', 'Refere-se à manutenção de vínculo continuado entre a equipe e a população ao longo do tempo, independente de doenças específicas.', 'Refere-se exclusivamente à capacidade de resolver a maioria dos problemas de saúde dentro da própria unidade básica.', 'Refere-se à oferta simultânea de múltiplos serviços especializados dentro de uma única unidade de atenção primária.'], correctIndex: 0, explanation: 'A coordenação do cuidado refere-se à capacidade da atenção primária de organizar e integrar o cuidado entre diferentes níveis e pontos da rede, evitando fragmentação, especialmente relevante no encaminhamento e retorno de informações entre especialistas. A manutenção de vínculo continuado ao longo do tempo descreve a longitudinalidade, atributo distinto; resolver a maioria dos problemas na própria unidade descreve a integralidade/resolutividade; a oferta simultânea de múltiplos serviços especializados não é atributo característico da atenção primária.' },
  { id: 'cermam_gerado26_092', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação à participação social no SUS, prevista pela Lei nº 8.142/1990, assinale a alternativa correta sobre os Conselhos de Saúde.', options: ['São instâncias colegiadas, permanentes e deliberativas, com representação paritária de usuários em relação aos demais segmentos.', 'Têm caráter exclusivamente consultivo, sem qualquer poder deliberativo.', 'São compostos exclusivamente por gestores públicos, sem participação de usuários ou trabalhadores.', 'Não têm qualquer papel na fiscalização da aplicação de recursos financeiros da saúde.'], correctIndex: 0, explanation: 'Os Conselhos de Saúde são instâncias colegiadas, permanentes e deliberativas, com representação paritária de usuários. Não têm caráter exclusivamente consultivo; não são compostos exclusivamente por gestores; têm papel de fiscalização dos recursos financeiros.' },
  { id: 'cermam_gerado26_093', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação à integralidade como princípio doutrinário do SUS, assinale a alternativa correta.', options: ['Compreende a articulação de ações de promoção, prevenção, tratamento e reabilitação, considerando o indivíduo em sua totalidade.', 'Restringe-se a ações curativas isoladas, sem qualquer componente preventivo ou de promoção.', 'Aplica-se exclusivamente ao nível hospitalar de atenção, sem relação com a atenção primária.', 'Significa que cada serviço de saúde deve oferecer isoladamente toda a gama de especialidades médicas existentes.'], correctIndex: 0, explanation: 'A integralidade compreende a articulação de promoção, prevenção, tratamento e reabilitação, considerando o indivíduo em sua totalidade. Não se restringe a ações curativas isoladas; não é exclusiva do nível hospitalar; não exige que cada serviço isolado ofereça toda a gama de especialidades, mas sim que a rede como um todo garanta esse cuidado integral.' },
  { id: 'cermam_gerado26_094', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação ao Programa Saúde na Escola (PSE), assinale a alternativa correta.', options: ['Constitui estratégia intersetorial entre saúde e educação, integrando ações de promoção da saúde, prevenção de agravos e cuidado a crianças e adolescentes no ambiente escolar.', 'É executado exclusivamente pelo setor de educação, sem qualquer participação das equipes de saúde da atenção primária.', 'Restringe-se à aplicação de vacinas nas escolas, sem outras ações de saúde.', 'Aplica-se exclusivamente a escolas da rede privada de ensino.'], correctIndex: 0, explanation: 'O PSE é estratégia intersetorial entre saúde e educação, integrando promoção, prevenção e cuidado no ambiente escolar. Não é executado exclusivamente pela educação, envolvendo as equipes de saúde da atenção primária; não se restringe à vacinação; aplica-se à rede pública de ensino, sendo essa sua principal abrangência.' },
  { id: 'cermam_gerado26_095', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação à Política Nacional de Humanização (PNH) do SUS, assinale a alternativa correta.', options: ['Busca promover mudanças nos modelos de atenção e gestão, valorizando os sujeitos envolvidos no processo de produção de saúde (usuários, trabalhadores e gestores).', 'Restringe-se a ações estéticas de melhoria da estrutura física das unidades de saúde.', 'Aplica-se exclusivamente ao ambiente hospitalar, sem relação com a atenção primária.', 'Tem como único objetivo a redução do tempo de espera em filas de atendimento.'], correctIndex: 0, explanation: 'A PNH busca promover mudanças nos modelos de atenção e gestão, valorizando usuários, trabalhadores e gestores. Não se restringe a ações estéticas estruturais; não é exclusiva do ambiente hospitalar; não tem como único objetivo a redução de filas, sendo um objetivo mais amplo de transformação das práticas de cuidado e gestão.' },
  { id: 'cermam_gerado26_096', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação à Classificação Internacional de Atenção Primária (CIAP-2), utilizada no registro de informações em saúde na Atenção Básica, assinale a alternativa correta.', options: ['Permite a codificação de motivos de consulta, problemas de saúde e procedimentos, organizados por capítulos correspondentes a sistemas orgânicos e componentes específicos.', 'É utilizada exclusivamente para codificação de procedimentos cirúrgicos hospitalares de alta complexidade.', 'Substitui integralmente a necessidade de registro em prontuário clínico do paciente.', 'Aplica-se exclusivamente a doenças infectocontagiosas de notificação compulsória.'], correctIndex: 0, explanation: 'A CIAP-2 permite codificar motivos de consulta, problemas de saúde e procedimentos na atenção primária, organizados por sistemas orgânicos. Não é utilizada para codificação de procedimentos cirúrgicos hospitalares de alta complexidade; não substitui o registro em prontuário, sendo complementar; não se restringe a doenças de notificação compulsória, aplicando-se a qualquer motivo de consulta na atenção primária.' },
  { id: 'cermam_gerado26_097', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação ao cuidado compartilhado de pacientes com múltiplas comorbidades crônicas na atenção primária, assinale a alternativa correta.', options: ['Deve considerar a priorização de problemas conforme impacto funcional e prognóstico, evitando polifarmácia desnecessária e fragmentação do cuidado entre múltiplos especialistas sem coordenação.', 'Deve encaminhar automaticamente o paciente a um especialista distinto para cada comorbidade identificada, sem qualquer coordenação pela equipe de referência.', 'Deve priorizar exclusivamente a comorbidade mais recentemente diagnosticada, ignorando as demais condições já estabelecidas.', 'Deve evitar qualquer registro compartilhado de informações entre os profissionais envolvidos no cuidado do paciente.'], correctIndex: 0, explanation: 'O cuidado compartilhado de múltiplas comorbidades deve priorizar problemas por impacto funcional e prognóstico, evitando polifarmácia e fragmentação sem coordenação, papel central da atenção primária. Encaminhar automaticamente sem coordenação fragmenta o cuidado; priorizar apenas a comorbidade mais recente ignora as demais condições relevantes; evitar registro compartilhado prejudica a continuidade e segurança do cuidado.' },
  { id: 'cermam_gerado26_098', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação à visita domiciliar realizada por equipe de Saúde da Família, assinale a alternativa correta.', options: ['É ferramenta importante para avaliação do contexto socioambiental e familiar do paciente, especialmente útil no cuidado de pacientes acamados, idosos frágeis e famílias em vulnerabilidade.', 'Deve ser realizada exclusivamente por solicitação médica formal, sem participação de outros membros da equipe multiprofissional.', 'Substitui integralmente a necessidade de consultas na unidade de saúde para qualquer condição clínica do paciente.', 'É restrita exclusivamente a situações de óbito domiciliar, sem outras indicações.'], correctIndex: 0, explanation: 'A visita domiciliar permite avaliar o contexto socioambiental e familiar, especialmente útil em acamados, idosos frágeis e famílias vulneráveis. Não é exclusiva de solicitação médica, envolvendo toda a equipe multiprofissional; não substitui integralmente as consultas na unidade; não é restrita a situações de óbito domiciliar.' },
  { id: 'cermam_gerado26_099', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Parasitologia', text: 'Criança de 5 anos, residente em área endêmica, com prurido anal noturno intenso, irritabilidade e distúrbio do sono, identificação de ovos característicos pelo método de fita adesiva perianal (Graham). Assinale o agente etiológico e o tratamento.', options: ['Enterobius vermicularis; albendazol ou mebendazol, com tratamento de todos os contactantes domiciliares.', 'Ascaris lumbricoides; albendazol isolado, sem necessidade de tratar os contactantes domiciliares.', 'Taenia solium; praziquantel isolado, sem relação com o método diagnóstico descrito.', 'Schistosoma mansoni; praziquantel, sem relação com prurido anal noturno.'], correctIndex: 0, explanation: 'Prurido anal noturno com ovos identificados pelo método de Graham são característicos da enterobíase, tratada com albendazol ou mebendazol, associado ao tratamento dos contactantes domiciliares pelo risco de reinfecção. Ascaris não causa esse prurido anal noturno característico nem é diagnosticado por esse método; a teníase não é diagnosticada pelo método de Graham; a esquistossomose não causa prurido anal noturno.' },
  { id: 'cermam_gerado26_100', banca: 'CERMAM', cycle: 'Ciclo Clínico', subject: 'Ginecologia & Obstetrícia', text: 'Adolescente de 15 anos, sexualmente ativa, procura consulta ginecológica sem os pais, com receio de que os responsáveis sejam informados. Assinale a conduta ética adequada.', options: ['Respeitar o sigilo e a autonomia da adolescente, informando-a sobre seus direitos, exceto em situações de risco grave previstas em lei.', 'Comunicar imediatamente os pais antes de qualquer atendimento à adolescente.', 'Recusar o atendimento até que a adolescente venha acompanhada de um responsável legal.', 'Informar que o sigilo médico não se aplica a adolescentes em nenhuma circunstância.'], correctIndex: 0, explanation: 'Adolescentes têm direito ao sigilo e à autonomia crescente sobre sua saúde, com quebra de sigilo reservada a situações de risco grave previstas em lei. Comunicar os pais obrigatoriamente pode afastar a adolescente do cuidado necessário; recusar o atendimento sem acompanhante prejudica a saúde da paciente; afirmar que o sigilo nunca se aplica contraria seus direitos reconhecidos.' },
];
